    StringBuilder currentOption = new StringBuilder();
    for (int i = 0; i < optName.length(); i++) {
        char c = optName.charAt(i);
        if (c == '=') {
            // Check the accumulated option name
            if (currentOption.length() > 0 && options.hasShortOption(currentOption.toString())) {
                return true;
            }
            // Skip the value part of the option
            while (i < optName.length() && optName.charAt(i) != '-') {
                i++;
