            if (i < optName.length()) {
                currentOption.setLength(0);
            }
        } else {
            currentOption.append(c);
            if (options.hasShortOption(currentOption.toString())) {
                return true;
            }
        }
    }
    // Final check for the last accumulated option
    return currentOption.length() > 0 && options.hasShortOption(currentOption.toString());
}

